import{_ as t,o as r,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"53. Rest Period After Overtime Recall","description":"","frontmatter":{"title":"53. Rest Period After Overtime Recall","eba":"Nurses and Midwives 2024-2028","topics":["hours","overtime","shift-work"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/53-rest-period-after-overtime-recall.md","filePath":"ebas/nurses-midwives/hours-of-work/53-rest-period-after-overtime-recall.md"}'),a={name:"ebas/nurses-midwives/hours-of-work/53-rest-period-after-overtime-recall.md"};function i(n,e,l,h,u,c){return r(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_53-rest-period-after-overtime-recall" tabindex="-1">53. Rest Period After Overtime Recall <a class="header-anchor" href="#_53-rest-period-after-overtime-recall" aria-label="Permalink to &quot;53. Rest Period After Overtime Recall&quot;">​</a></h1><p>This clause does not apply to recall work performed under <a href="/eba/ebas/nurses-midwives/hours-of-work/51-recall-without-return-to-workplace.html">clause 51</a> (Recall Without Return to Workplace).</p><p><strong>53.1</strong> When overtime is worked the Employees should have at least 10 consecutive hours off duty between finishing the overtime and the next successive shift.</p><p><strong>53.2</strong> Unless <a href="/eba/ebas/nurses-midwives/hours-of-work/54-rest-period-after-excessive-hours.html">clause 54</a> applies:</p><p><strong>(a)</strong> an Employee who works so much overtime that the Employee would not have had at least 10 consecutive hours off duty between the completion of overtime and the commencement of the next rostered shift then, subject to this clause, the Employee will be released after completion of overtime until the Employee has had 10 consecutive hours off duty, without loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>(b)</strong> if an Employee is required by the Employer to resume or to continue to work without having had 10 consecutive hours off duty, the Employee will be paid at the rate of double time until released from duty for 10 consecutive hours, without loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>53.3</strong> If the requirements at clause 53.2 result in an Employee commencing ordinary hours with 3 or fewer hours remaining in their rostered shift, the Employee will be paid for the entire rostered shift without any requirement to attend for duty.</p><p><strong>53.4</strong> The Employer is not to change an Employee’s rostered shift/s to avoid the requirements at clause 53.2.</p><p>Plain language terms: 10 hour break, fatigue break, rest between shifts.</p>',9)])])}const f=t(a,[["render",i]]);export{m as __pageData,f as default};
